+                                    disabled="@isSaving">Save</button>
+                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
+                        </div>
+                    </div>
+                }
+                else
+                {
+                    <button class="btn btn-sm btn-outline-primary add-task-btn"
+                            @onclick="() => StartAdd(column)">+ Add Task</button>
+                }
+            </div>
+        }
+    </div>
+}
