+    private List<TaskItem> GetColumnTasks(string status) =>
+        allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status) =>
+        allTasks
+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(searchQuery) ||
+                         t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private int GetColumnIndex(string status) => Array.IndexOf(columns, status);
+
+    private async Task MoveTask(TaskItem task, int direction)
+    {
+        var currentIndex = GetColumnIndex(task.Status);
+        var newIndex = currentIndex + direction;
+        if (newIndex < 0 || newIndex >= columns.Length) return;
+
+        isMoving = true;
+        try
+        {
+            var newStatus = columns[newIndex];
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            // Replace task in list with updated status
+            var idx = allTasks.FindIndex(t => t.Id == task.Id);
+            if (idx >= 0)
+                allTasks[idx] = task with { Status = newStatus };
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            isMoving = false;
+        }
+    }
