+    {
+        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null) return;
+
+        isSaving = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
+            // The service creates with default status; override to the target column
+            allTasks.Add(created with { Status = addingToColumn });
+
+            if (created.Status != addingToColumn)
+                await TaskService.UpdateTaskStatusAsync(created.Id, addingToColumn);
+
+            addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+}
